"use client";

import { cn } from "@/lib/utils";
import {
  AnimatePresence,
  motion,
  useAnimation,
} from "framer-motion";
import {
  LucideIcon,
  Mail,
  MessageSquare,
  Plus,
  Settings,
  Share2,
} from "lucide-react";
import * as React from "react";

interface OrbitAction {
  icon: LucideIcon;
  label: string;
  onClick?: () => void;
  color?: string; // Optional: e.g. "text-blue-500", "bg-emerald-500/10"
}

interface CommandOrbitProps {
  actions?: OrbitAction[];
  className?: string;
  radius?: number;
  showLabels?: boolean;
}

const defaultActions: OrbitAction[] = [
  { icon: MessageSquare, label: "Chat", color: "text-blue-500" },
  { icon: Share2, label: "Share", color: "text-purple-500" },
  { icon: Mail, label: "Email", color: "text-rose-500" },
  { icon: Settings, label: "Config", color: "text-zinc-500" },
];

export function CommandOrbit({
  actions = defaultActions,
  className,
  radius = 95,
  showLabels = true,
}: CommandOrbitProps) {
  const [isOpen, setIsOpen] = React.useState(false);

  return (
    <div
      className={cn(
        "relative flex items-center justify-center p-24 select-none",
        className,
      )}
    >
      {/* Dynamic Background Rings & Paths */}
      <AnimatePresence>
        {isOpen && (
          <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
            {/* The Main Orbit Path */}
            <motion.div
              initial={{ opacity: 0, scale: 0.8 }}
              animate={{ opacity: 1, scale: 1 }}
              exit={{ opacity: 0, scale: 0.9 }}
              className="absolute rounded-full border border-zinc-200/50 dark:border-zinc-800/50"
              style={{ width: radius * 2, height: radius * 2 }}
            >
              <div className="absolute inset-0 rounded-full border border-dashed border-zinc-300/30 dark:border-zinc-700/20" />
            </motion.div>

            {/* Pulsing Outer Ring */}
            <motion.div
              initial={{ opacity: 0, scale: 1 }}
              animate={{ opacity: [0, 0.2, 0], scale: 1.4 }}
              transition={{ duration: 2, repeat: Infinity, ease: "easeOut" }}
              className="absolute rounded-full border border-zinc-400/30 dark:border-zinc-500/20"
              style={{ width: radius * 2, height: radius * 2 }}
            />
          </div>
        )}
      </AnimatePresence>

      {/* Action Items */}
      <AnimatePresence>
        {isOpen &&
          actions.map((action, index) => {
            const angle = (index * 360) / actions.length - 90;
            const x = Math.cos((angle * Math.PI) / 180) * radius;
            const y = Math.sin((angle * Math.PI) / 180) * radius;

            return (
              <motion.button
                key={action.label}
                initial={{ x: 0, y: 0, scale: 0, opacity: 0, rotate: -45 }}
                animate={{
                  x,
                  y,
                  scale: 1,
                  opacity: 1,
                  rotate: 0,
                  transition: {
                    type: "spring",
                    stiffness: 240,
                    damping: 18,
                    delay: index * 0.05,
                  },
                }}
                exit={{
                  x: 0,
                  y: 0,
                  scale: 0,
                  opacity: 0,
                  transition: {
                    duration: 0.2,
                    delay: (actions.length - index) * 0.03,
                  },
                }}
                whileHover={{ 
                  scale: 1.2,
                  y: y * 1.05, // Slight "outward" push on hover
                  x: x * 1.05,
                  zIndex: 100
                }}
                whileTap={{ scale: 0.9 }}
                onClick={() => {
                  action.onClick?.();
                  setIsOpen(false);
                }}
                className={cn(
                  "absolute z-50 group flex h-14 w-14 items-center justify-center rounded-[20px]",
                  "bg-white/90 dark:bg-zinc-950/90 backdrop-blur-2xl",
                  "border border-zinc-200/50 dark:border-zinc-800/50",
                  "shadow-[0_8px_24px_rgba(0,0,0,0.06)] dark:shadow-[0_16px_48px_rgba(0,0,0,0.4)]",
                  "hover:border-zinc-300 dark:hover:border-zinc-700",
                  "transition-all duration-300 ease-out",
                )}
              >
                {/* Action Icon */}
                <action.icon className={cn(
                  "w-6 h-6 transition-transform duration-300 group-hover:scale-110",
                  action.color || "text-zinc-600 dark:text-zinc-400 group-hover:text-zinc-900 dark:group-hover:text-zinc-100"
                )} />

                {/* Refined Tooltip Label */}
                {showLabels && (
                  <span className="absolute -bottom-10 opacity-0 group-hover:opacity-100 transition-all duration-300 pointer-events-none whitespace-nowrap bg-zinc-900 dark:bg-zinc-100 text-zinc-100 dark:text-zinc-900 px-2.5 py-1 rounded-lg text-[11px] font-semibold tracking-wide shadow-xl translate-y-2 group-hover:translate-y-0">
                    {action.label}
                  </span>
                )}

                {/* Glossy Overlay */}
                <div className="absolute inset-0 rounded-[20px] bg-gradient-to-tr from-white/10 to-transparent pointer-events-none" />
                <div className="absolute inset-0 rounded-[20px] border-t border-white/40 dark:border-white/5 pointer-events-none" />
              </motion.button>
            );
          })}
      </AnimatePresence>

      {/* Central Command Button (The Core) */}
      <motion.button
        onClick={() => setIsOpen(!isOpen)}
        whileHover={{ scale: 1.05 }}
        whileTap={{ scale: 0.95 }}
        className={cn(
          "relative z-[60] flex h-20 w-20 items-center justify-center rounded-full transition-all duration-700",
          "bg-white dark:bg-zinc-900",
          "border border-zinc-200 dark:border-zinc-800",
          "shadow-[0_20px_40px_rgba(0,0,0,0.1)] dark:shadow-[0_20px_50px_rgba(0,0,0,0.5)]",
          "overflow-hidden",
          isOpen ? "ring-8 ring-zinc-100/50 dark:ring-zinc-800/20" : "ring-0",
        )}
      >
        {/* Animated Background Mesh */}
        <motion.div
           animate={{
             rotate: [0, 360],
           }}
           transition={{ duration: 20, repeat: Infinity, ease: "linear" }}
           className="absolute inset-[-50%] bg-[radial-gradient(circle_at_50%_50%,rgba(0,0,0,0.03)_0%,transparent_50%)] dark:bg-[radial-gradient(circle_at_50%_50%,rgba(255,255,255,0.02)_0%,transparent_50%)] pointer-events-none"
        />

        {/* Central Icon */}
        <div className="relative">
          <motion.div
            animate={{ 
              rotate: isOpen ? 135 : 0,
              scale: isOpen ? 0.9 : 1
            }}
            transition={{ type: "spring", stiffness: 300, damping: 22 }}
          >
            <Plus className="w-10 h-10 text-zinc-900 dark:text-zinc-100" strokeWidth={1.5} />
          </motion.div>
        </div>

        {/* Inner Decorative Rings */}
        <div className="absolute inset-3 rounded-full border border-zinc-100 dark:border-zinc-800 pointer-events-none" />
        <div className="absolute inset-4 rounded-full border border-dashed border-zinc-200/50 dark:border-zinc-700/20 pointer-events-none" />

        {/* Pulse Effect (When closed) */}
        {!isOpen && (
          <motion.div
            initial={{ opacity: 0, scale: 1 }}
            animate={{ opacity: [0, 0.4, 0], scale: 1.2 }}
            transition={{ duration: 2.5, repeat: Infinity }}
            className="absolute inset-0 rounded-full bg-zinc-400/10 dark:bg-zinc-500/10 pointer-events-none"
          />
        )}
      </motion.button>

      {/* Screen Backdrop Backdrop Blur */}
      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onClick={() => setIsOpen(false)}
            className="fixed inset-0 z-40 bg-zinc-950/10 dark:bg-zinc-950/40 backdrop-blur-[4px]"
          />
        )}
      </AnimatePresence>
    </div>
  );
}
